/**
 * ============================================================
 * OncoWatch CI Triage — Build AI Input
 * Version: 3.0.0
 * Stage: Production
 * ============================================================
 * Responsibilities:
 *  1. Normalize and validate raw signal fields
 *  2. Assess pre-LLM signal quality & route to correct model
 *  3. Build structured features object
 *  4. Compress and sanitize context text
 *  5. Construct system + user prompts (override-aware)
 *  6. Emit final OpenRouter body + full enriched item
 * ============================================================
 */

// ─────────────────────────────────────────────
// 0. CONSTANTS
// ─────────────────────────────────────────────
const PIPELINE_VERSION    = '3.0.0';
const MAX_CONTEXT_CHARS   = 6000;
const MAX_SUMMARY_CHARS   = 1000;
const MAX_TOKENS          = 800;
const FALLBACK_CONFIDENCE = 0.3;

const VALID_IMPACT_LEVELS      = new Set(['HIGH', 'MED', 'LOW', 'UNSET']);
const VALID_SIGNAL_TYPES       = new Set(['trial_update', 'regulatory', 'publication', 'conference', 'safety', 'news', 'other']);
const VALID_OVERRIDE_STATUSES  = new Set(['escalated', 'downgraded', 'locked', 'none']);
const VALID_ACTIONS            = new Set(['ESCALATE', 'MONITOR', 'DISMISS', 'REVIEW']);

const MODELS = {
  FLAGSHIP:   'openai/gpt-4.1',
  STANDARD:   'openai/gpt-4.1-mini',
  FAST:       'openai/gpt-4.1-nano',
};

// ─────────────────────────────────────────────
// 1. HELPERS
// ─────────────────────────────────────────────
const safe = (v, fallback = '') => {
  if (v === null || v === undefined) return fallback;
  return String(v)
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
    .replace(/\s+/g, ' ')
    .trim() || fallback;
};

const safeUpper = (v, fallback = 'UNKNOWN') =>
  safe(v, fallback).toUpperCase();

const safeLower = (v, fallback = 'unknown') =>
  safe(v, fallback).toLowerCase();

const toNumberOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const clamp = (n, min, max) => Math.max(min, Math.min(n, max));

const isoNow = () => new Date().toISOString();

const truncate = (str, maxLen) =>
  str.length > maxLen
    ? str.slice(0, maxLen) + '\n...[truncated]'
    : str;

const coalesceStr = (...args) => {
  for (const v of args) {
    const s = safe(v);
    if (s) return s;
  }
  return '';
};

// ─────────────────────────────────────────────
// 2. INPUT
// ─────────────────────────────────────────────
const s = $input.item.json;

if (!s || typeof s !== 'object') {
  throw new Error('[OncoWatch] Input item is null or not an object.');
}

// ─────────────────────────────────────────────
// 3. NORMALIZE CORE FIELDS
// ─────────────────────────────────────────────
const signalId    = coalesceStr(s.source_id, s.id) || null;
const drug        = safe(coalesceStr(s.key_drug, s.drug_name), 'Unknown');
const indication  = safe(coalesceStr(s.key_indication, s.indication), 'Unknown');
const sponsor     = safe(s.sponsor, 'Unknown');
const phase       = safe(coalesceStr(s.phase, s.trial_phase), 'NA');
const status      = safe(coalesceStr(s.status, s.trial_status), 'NA');
const title       = safe(s.title, 'NA');
const url         = safe(s.url, '');
const source      = safe(s.source, 'unknown');

// Signal type: validate against whitelist, default 'other'
const rawSignalType = safeLower(coalesceStr(s.signal_type, 'other'));
const signalType    = VALID_SIGNAL_TYPES.has(rawSignalType) ? rawSignalType : 'other';

const competitor = !!s.competitor_flag;
const isUrgent   = !!s.is_urgent;

// Impact level: validate against whitelist, default 'UNSET'
const rawPrevLevel   = safeUpper(coalesceStr(s.impact_level, s.previous_impact_level, 'UNSET'));
const previousImpactLevel = VALID_IMPACT_LEVELS.has(rawPrevLevel) ? rawPrevLevel : 'UNSET';
const previousImpactScore = toNumberOrNull(s.impact_score ?? s.previous_impact_score);

// Override
const rawOverride     = safeLower(s.override_status || 'none');
const overrideStatus  = VALID_OVERRIDE_STATUSES.has(rawOverride) ? rawOverride : 'none';
const overrideBy      = safe(s.override_by, '');
const overrideReason  = safe(s.override_reason, '');
const overrideAt      = s.override_at || null;

// Timestamps and versioning
const ingestedAt  = s.ingested_at || null;
const firstSeenAt = s.first_seen_at || null;
const lastSeenAt  = s.last_seen_at || null;
const version     = Number.isInteger(s.version) ? s.version : 1;
const scoringVer  = Number.isInteger(s.scoring_version) ? s.scoring_version : 0;

// Priority base
const priorityBase = toNumberOrNull(s.priority_base);
const ageHours     = toNumberOrNull(s.age_hours);

// ─────────────────────────────────────────────
// 4. CONTEXT EXTRACTION + COMPRESSION
// ─────────────────────────────────────────────
const rawBlocks = [];

// Primary: raw_text (string or object)
if (s.raw_text) {
  if (typeof s.raw_text === 'string') {
    rawBlocks.push(truncate(s.raw_text, MAX_CONTEXT_CHARS));
  } else if (typeof s.raw_text === 'object') {
    const CTX_KEYS = ['abstract', 'summary', 'description', 'title', 'notes', 'body', 'text'];
    for (const k of CTX_KEYS) {
      if (s.raw_text[k]) rawBlocks.push(safe(s.raw_text[k]));
    }
    if (rawBlocks.length === 0) {
      try { rawBlocks.push(JSON.stringify(s.raw_text)); }
      catch (_) { rawBlocks.push('[raw_text: unserializable object]'); }
    }
  }
}

// Fallback: ai_summary, title, indication
if (rawBlocks.length === 0) {
  if (s.ai_summary) rawBlocks.push(truncate(safe(s.ai_summary), MAX_SUMMARY_CHARS));
  if (title && title !== 'NA') rawBlocks.push(`Title: ${title}`);
  if (indication && indication !== 'Unknown') rawBlocks.push(`Indication: ${indication}`);
  if (drug && drug !== 'Unknown') rawBlocks.push(`Drug: ${drug}`);
  if (sponsor && sponsor !== 'Unknown') rawBlocks.push(`Sponsor: ${sponsor}`);
}

const combinedRaw = truncate(rawBlocks.join('\n\n'), MAX_CONTEXT_CHARS);

// ─────────────────────────────────────────────
// 5. PRE-LLM SIGNAL QUALITY ASSESSMENT
// ─────────────────────────────────────────────
let qualityScore = 0; // 0–10
const qualityFlags = [];

if (drug !== 'Unknown')        { qualityScore += 2; } else { qualityFlags.push('missing_drug'); }
if (indication !== 'Unknown')  { qualityScore += 2; } else { qualityFlags.push('missing_indication'); }
if (sponsor !== 'Unknown')     { qualityScore += 1; } else { qualityFlags.push('missing_sponsor'); }
if (phase !== 'NA')            { qualityScore += 1; } else { qualityFlags.push('missing_phase'); }
if (combinedRaw.length > 200)  { qualityScore += 2; } else { qualityFlags.push('sparse_context'); }
if (url)                       { qualityScore += 1; } else { qualityFlags.push('missing_url'); }
if (title && title !== 'NA')   { qualityScore += 1; } else { qualityFlags.push('missing_title'); }

const contextQuality =
  qualityScore >= 8 ? 'RICH' :
  qualityScore >= 5 ? 'ADEQUATE' :
  qualityScore >= 3 ? 'SPARSE' : 'MINIMAL';

// ─────────────────────────────────────────────
// 6. GUARDRAILS + OVERRIDE LOGIC
// ─────────────────────────────────────────────
const hasStrongOverride =
  overrideStatus === 'escalated' ||
  overrideStatus === 'downgraded' ||
  overrideStatus === 'locked';

const safetyFloorLevel = hasStrongOverride ? previousImpactLevel : 'LOW';

// ─────────────────────────────────────────────
// 7. MODEL ROUTING
// ─────────────────────────────────────────────
let modelRoutingReason;
let model;

if (isUrgent && competitor) {
  model = MODELS.FLAGSHIP;
  modelRoutingReason = 'urgent_AND_competitor → flagship';
} else if (isUrgent || competitor) {
  model = MODELS.FLAGSHIP;
  modelRoutingReason = 'urgent_OR_competitor → flagship';
} else if (hasStrongOverride) {
  model = MODELS.STANDARD;
  modelRoutingReason = 'strong_human_override → standard';
} else if (contextQuality === 'MINIMAL') {
  model = MODELS.FAST;
  modelRoutingReason = 'minimal_context → fast';
} else {
  model = MODELS.STANDARD;
  modelRoutingReason = 'default → standard';
}

// ─────────────────────────────────────────────
// 8. TEMPERATURE SELECTION
// ─────────────────────────────────────────────
let baseTemp;
if (isUrgent) {
  baseTemp = 0.15;
} else if (previousImpactLevel === 'HIGH') {
  baseTemp = 0.2;
} else if (contextQuality === 'MINIMAL') {
  baseTemp = 0.4;
} else {
  baseTemp = 0.3;
}
const temperature = clamp(baseTemp, 0, 0.7);

// ─────────────────────────────────────────────
// 9. FEATURES OBJECT (model-facing)
// ─────────────────────────────────────────────
const features = {
  signal_id: signalId,
  drug,
  indication,
  sponsor,
  source,
  trial_phase: phase,
  trial_status: status,
  current_signal_type: signalType,
  competitor_flag: competitor,
  previous_impact_level: previousImpactLevel,
  previous_impact_score: previousImpactScore,
  override_status: overrideStatus,
  override_by: overrideBy || null,
  override_reason: overrideReason || null,
  override_at: overrideAt,
  is_urgent: isUrgent,
  priority_base: priorityBase,
  age_hours: ageHours,
  context_quality: contextQuality,
  quality_score: qualityScore,
  quality_flags: qualityFlags,
  ingested_at: ingestedAt,
  first_seen_at: firstSeenAt,
  last_seen_at: lastSeenAt,
  version,
  scoring_version: scoringVer,
  url: url || null,
};

// ─────────────────────────────────────────────
// 10. SYSTEM PROMPT (override-aware, structured)
// ─────────────────────────────────────────────
const systemPrompt = `
You are an oncology competitive intelligence (CI) triage assistant for a large pharmaceutical company.

ROLE:
- You analyze CI signals from clinical trial registries, regulatory filings, publications, news, and conferences.
- You produce structured triage scores to help medical affairs and CI teams prioritize responses.

INPUT:
1) A structured JSON "features" object describing a CI signal.
2) Unstructured context text (trial protocol, abstract, news article, or registry entry).

TASKS:
- Re-assess "impact_level" ∈ {"HIGH","MED","LOW"} using both features and context.
- Assign "impact_score" ∈ [0,10] (10 = highest strategic threat or opportunity).
- Refine "signal_type" ∈ {"trial_update","regulatory","publication","conference","safety","news","other"}.
- Decide "competitor_flag" (true/false) based on sponsor, drug, and indication.
- Generate "ai_summary": 2–4 concise sentences tailored for pharma CI / medical affairs.
- Set "recommended_action" ∈ {"ESCALATE","MONITOR","DISMISS","REVIEW"}.
- Provide "score_breakdown":
  - "drivers": array of 2–6 short phrases raising the score.
  - "risks": array of 1–5 short phrases capturing uncertainty / caveats.
  - "confidence": float in [0,1].

GUARDRAILS:
- Prefer MED over LOW when there is credible signal with any supporting context.
- If context_quality = "MINIMAL" or "SPARSE", keep confidence ≤ 0.45.
- If override_status = "escalated" or "locked", do NOT downgrade unless evidence is overwhelming.
- If override_status = "downgraded", do NOT upgrade unless evidence strongly justifies it.
- Never add commentary, prose, or markdown outside the JSON.

METADATA CONTEXT:
- signal_id: ${signalId || 'NA'}
- override_status: ${overrideStatus}
- previous_impact_level: ${previousImpactLevel}
- previous_impact_score: ${previousImpactScore ?? 'NA'}
- context_quality: ${contextQuality} (score: ${qualityScore}/10)
- quality_flags: ${qualityFlags.length > 0 ? qualityFlags.join(', ') : 'none'}
- safety_floor_impact_level: ${safetyFloorLevel}
- model_routing_reason: ${modelRoutingReason}
- pipeline_version: ${PIPELINE_VERSION}

OUTPUT CONTRACT:
Return ONLY a single strict JSON object with EXACT keys:
{
  "impact_level": string,
  "impact_score": number,
  "signal_type": string,
  "competitor_flag": boolean,
  "ai_summary": string,
  "recommended_action": string,
  "score_breakdown": {
    "drivers": string[],
    "risks": string[],
    "confidence": number
  }
}
`.trim();

// ─────────────────────────────────────────────
// 11. USER PROMPT
// ─────────────────────────────────────────────
const aiInputText = `
INSTRUCTIONS:
${systemPrompt}

FEATURES (JSON):
${JSON.stringify(features, null, 2)}

CONTEXT:
${combinedRaw || 'No context available.'}
`.trim();

// ─────────────────────────────────────────────
// 12. OPENROUTER REQUEST BODY
// ─────────────────────────────────────────────
const openrouterBody = {
  model,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: aiInputText }
  ],
  response_format: { type: 'json_object' },
  temperature,
  top_p: 0.9,
  max_tokens: MAX_TOKENS,
  metadata: {
    client: 'OncoWatch',
    task: 'ci_ai_triage',
    pipeline_version: PIPELINE_VERSION,
    signal_id: signalId || null,
    drug,
    indication,
    sponsor,
    trial_phase: phase,
    trial_status: status,
    source,
    competitor_flag_input: competitor,
    urgent_input: isUrgent,
    override_status: overrideStatus,
    override_by: overrideBy || null,
    override_reason: overrideReason || null,
    previous_impact_level: previousImpactLevel,
    previous_impact_score: previousImpactScore,
    context_quality: contextQuality,
    quality_score: qualityScore,
    quality_flags: qualityFlags,
    model_routing_reason: modelRoutingReason,
    scoring_version: scoringVer,
    payload_version: version,
    first_seen_at: firstSeenAt,
    last_seen_at: lastSeenAt,
    ingested_at: ingestedAt,
    source_url: url || null,
    built_at: isoNow(),
  }
};

// ─────────────────────────────────────────────
// 13. RETURN ENRICHED ITEM
// ─────────────────────────────────────────────
return [
  {
    json: {
      ...s,
      ai_features: features,
      ai_input_text: aiInputText,
      openrouter_body: openrouterBody,
      _meta: {
        pipeline_version: PIPELINE_VERSION,
        model_selected: model,
        model_routing_reason: modelRoutingReason,
        context_quality: contextQuality,
        quality_score: qualityScore,
        quality_flags: qualityFlags,
        temperature,
        built_at: isoNow(),
      }
    }
  }
];

/**
 * ============================================================
 * OncoWatch CI Triage — Merge AI Output
 * Version: 3.2.0
 * No Merge node required.
 * Reads HTTP response from $input, original signal from $('Build AI Input')
 * ============================================================
 */

// ─────────────────────────────────────────────
// 1. GET BOTH DATA SOURCES
// ─────────────────────────────────────────────

// HTTP response from the node immediately before this one
const httpRaw = $input.item.json;

// Original enriched signal — pulled directly from the Build AI Input node
// NOTE: Change 'Build AI Input' below to match your exact node name
let original;
try {
  original = $('Build AI Input').item.json;
} catch (e) {
  throw new Error(
    '[OncoWatch] Merge: Could not read "Build AI Input" node. ' +
    'Check the node name matches exactly. Error: ' + e.message
  );
}

// ─────────────────────────────────────────────
// 2. VALIDATE
// ─────────────────────────────────────────────
if (!httpRaw || typeof httpRaw !== 'object') {
  throw new Error('[OncoWatch] Merge: HTTP response is null or not an object.');
}

if (!original || typeof original !== 'object') {
  throw new Error('[OncoWatch] Merge: Original signal is null or not an object.');
}

// ─────────────────────────────────────────────
// 3. EXTRACT LLM CONTENT
// ─────────────────────────────────────────────
let content = null;

// Shape A: standard chat completions
if (
  Array.isArray(httpRaw.choices) &&
  httpRaw.choices.length > 0 &&
  httpRaw.choices[0]?.message?.content
) {
  content = httpRaw.choices[0].message.content;
}

// Shape B: streaming delta
if (
  content === null &&
  Array.isArray(httpRaw.choices) &&
  httpRaw.choices.length > 0 &&
  httpRaw.choices[0]?.delta?.content
) {
  content = httpRaw.choices[0].delta.content;
}

// Shape C: raw.result wrapper
if (content === null && httpRaw.result !== undefined) {
  content = httpRaw.result;
}

// Shape D: already parsed object
if (content === null && httpRaw.impact_level) {
  content = httpRaw;
}

if (content === null) {
  throw new Error(
    '[OncoWatch] Merge: Could not find LLM content. HTTP keys: ' +
    Object.keys(httpRaw).join(', ')
  );
}

// ─────────────────────────────────────────────
// 4. PARSE JSON
// ─────────────────────────────────────────────
let payload;
if (typeof content === 'string') {
  const cleaned = content
    .trim()
    .replace(/^```json[\r\n]*/i, '')
    .replace(/^```[\r\n]*/,       '')
    .replace(/```$/,               '')
    .trim();
  try {
    payload = JSON.parse(cleaned);
  } catch (e) {
    throw new Error(
      '[OncoWatch] Merge: JSON parse failed — ' + e.message +
      ' | content(trunc): ' + cleaned.slice(0, 400)
    );
  }
} else if (typeof content === 'object' && content !== null) {
  payload = content;
} else {
  throw new Error('[OncoWatch] Merge: Unexpected content type: ' + typeof content);
}

// ─────────────────────────────────────────────
// 5. HELPERS
// ─────────────────────────────────────────────
const numOr = (v, fallback) => {
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};
const clamp = (n, min, max) => Math.max(min, Math.min(n, max));

const VALID_IMPACT  = new Set(['HIGH', 'MED', 'LOW']);
const VALID_ACTIONS = new Set(['ESCALATE', 'MONITOR', 'DISMISS', 'REVIEW']);
const VALID_TYPES   = new Set(['trial_update','regulatory','publication','conference','safety','news','other']);

const safeImpact = (v) => { const u = String(v||'').toUpperCase(); return VALID_IMPACT.has(u)  ? u : 'LOW';     };
const safeAction = (v) => { const u = String(v||'').toUpperCase(); return VALID_ACTIONS.has(u) ? u : 'MONITOR'; };
const safeType   = (v) => { const l = String(v||'').toLowerCase(); return VALID_TYPES.has(l)   ? l : 'other';   };

// ─────────────────────────────────────────────
// 6. NORMALIZE LLM OUTPUT
// ─────────────────────────────────────────────
const impactLevel = safeImpact(payload.impact_level);
const impactScore = clamp(numOr(payload.impact_score, 0), 0, 10);
const signalType  = safeType(payload.signal_type);
const compFlag    = !!payload.competitor_flag;
const aiSummary   = String(payload.ai_summary || '').trim();
const recAction   = safeAction(payload.recommended_action);

const scoreBreakdown = {
  drivers:    Array.isArray(payload.score_breakdown?.drivers) ? payload.score_breakdown.drivers.map(String) : [],
  risks:      Array.isArray(payload.score_breakdown?.risks)   ? payload.score_breakdown.risks.map(String)   : [],
  confidence: clamp(numOr(payload.score_breakdown?.confidence, 0.3), 0, 1)
};

// ─────────────────────────────────────────────
// 7. PULL META FROM ORIGINAL ITEM
// ─────────────────────────────────────────────
const meta     = original._meta           || {};
const features = original.ai_features     || {};
const orBody   = original.openrouter_body || {};

// ─────────────────────────────────────────────
// 8. BUILD FULLY MERGED OUTPUT
// ─────────────────────────────────────────────
const merged = {
  // Original signal fields
  id:                 original.id               || null,
  source_id:          original.source_id        || null,
  source:             original.source           || null,
  title:              original.title            || null,
  drug_name:          original.drug_name        || features.drug         || null,
  key_drug:           original.key_drug         || features.drug         || null,
  indication:         original.indication       || features.indication   || null,
  key_indication:     original.key_indication   || features.indication   || null,
  sponsor:            original.sponsor          || features.sponsor      || null,
  phase:              original.phase            || features.trial_phase  || null,
  status:             original.status           || features.trial_status || null,
  url:                original.url              || features.url          || null,
  raw_text:           original.raw_text         || null,
  ingested_at:        original.ingested_at      || null,
  first_seen_at:      original.first_seen_at    || null,
  last_seen_at:       original.last_seen_at     || null,
  version:            original.version          ?? null,
  scoring_version:    original.scoring_version  ?? null,
  override_status:    original.override_status  || 'none',
  override_by:        original.override_by      || null,
  override_reason:    original.override_reason  || null,
  override_at:        original.override_at      || null,
  is_urgent:          original.is_urgent        ?? false,
  priority_base:      original.priority_base    ?? null,
  age_hours:          original.age_hours        ?? null,
  daily_sent:         original.daily_sent       ?? false,
  weekly_sent:        original.weekly_sent      ?? false,
  retry_count:        original.retry_count      ?? 0,

  // AI triage outputs
  competitor_flag:    compFlag,
  impact_level:       impactLevel,
  impact_score:       impactScore,
  signal_type:        signalType,
  ai_summary:         aiSummary,
  recommended_action: recAction,
  score_breakdown:    scoreBreakdown,
  ai_processed:       true,
  processed:          true,
  refusal:            payload.refusal   ?? null,
  reasoning:          payload.reasoning ?? null,

  // Observability block — all from original._meta (not OpenRouter metadata)
  _triage_meta: {
    model_used:           httpRaw.model                   || orBody.model               || null,
    model_routing_reason: meta.model_routing_reason       || null,
    context_quality:      meta.context_quality            || features.context_quality   || null,
    quality_score:        meta.quality_score              ?? features.quality_score     ?? null,
    quality_flags:        meta.quality_flags              || features.quality_flags     || [],
    pipeline_version:     meta.pipeline_version           || null,
    temperature_used:     meta.temperature                ?? null,
    prompt_tokens:        httpRaw.usage?.prompt_tokens    ?? null,
    completion_tokens:    httpRaw.usage?.completion_tokens ?? null,
    total_tokens:         httpRaw.usage?.total_tokens     ?? null,
    merged_at:            new Date().toISOString(),
  }
};

return [{ json: merged }];

/**
 * ╔══════════════════════════════════════════════════════════════════╗
 * ║   OncoWatch CI Triage — Restore Signal + Advanced Pre-Router    ║
 * ║   Version  : 5.0.0                                              ║
 * ║   Stage    : Production / Investor-Grade                        ║
 * ║   Author   : OncoWatch Pipeline Engine                          ║
 * ╠══════════════════════════════════════════════════════════════════╣
 * ║  Responsibilities:                                              ║
 * ║  1.  Restore full CI signal after Update Signal node            ║
 * ║  2.  Validate + sanitize every field                            ║
 * ║  3.  Compute composite priority score (7-factor model)          ║
 * ║  4.  Determine route tier (9-tier system)                       ║
 * ║  5.  Assign alert channels per tier                             ║
 * ║  6.  Compute notification priority (P0–P4)                      ║
 * ║  7.  Detect override compliance violations                      ║
 * ║  8.  Generate audit trail entry                                 ║
 * ║  9.  Compute signal velocity (version-based change rate)        ║
 * ║  10. Emit enriched item for Switch node                         ║
 * ╚══════════════════════════════════════════════════════════════════╝
 */

'use strict';

// ══════════════════════════════════════════════════════════════════
// 0. PIPELINE CONSTANTS
// ══════════════════════════════════════════════════════════════════
const PIPELINE_VERSION           = '5.0.0';
const CRITICAL_PRIORITY_THRESHOLD = 9.0;
const HIGH_PRIORITY_THRESHOLD     = 7.0;
const MED_ELEVATED_THRESHOLD      = 5.5;
const URGENT_AGE_HOURS_THRESHOLD  = 48;
const CONFIDENCE_ALERT_MIN        = 0.60;
const CONFIDENCE_HIGH_MIN         = 0.75;
const MAX_RETRY_AI                = 3;
const MAX_RETRY_DB                = 5;

const ROUTE_TIERS = Object.freeze({
  CRITICAL        : 'CRITICAL',
  HIGH_COMPETITOR : 'HIGH_COMPETITOR',
  HIGH            : 'HIGH',
  MED_ELEVATED    : 'MED_ELEVATED',
  MED             : 'MED',
  LOW             : 'LOW',
  DISMISS         : 'DISMISS',
  AI_FAILED       : 'AI_FAILED',
  DB_FAILED       : 'DB_FAILED',
});

const NOTIF_PRIORITY = Object.freeze({
  CRITICAL        : 'P0',
  HIGH_COMPETITOR : 'P1',
  HIGH            : 'P1',
  MED_ELEVATED    : 'P2',
  MED             : 'P3',
  LOW             : 'P4',
  DISMISS         : 'P5',
  AI_FAILED       : 'P1',
  DB_FAILED       : 'P0',
});

const CHANNEL_MAP = Object.freeze({
  CRITICAL        : ['slack_exec', 'slack_medical_affairs', 'slack_ci_team', 'email_exec', 'pagerduty'],
  HIGH_COMPETITOR : ['slack_ci_team', 'slack_medical_affairs', 'email_ci_team'],
  HIGH            : ['slack_medical_affairs', 'slack_ci_team'],
  MED_ELEVATED    : ['slack_ci_team'],
  MED             : ['digest_daily'],
  LOW             : ['digest_weekly'],
  DISMISS         : ['archive'],
  AI_FAILED       : ['slack_ops', 'pagerduty'],
  DB_FAILED       : ['slack_ops', 'pagerduty', 'email_ops'],
});

const VALID_IMPACT_LEVELS  = new Set(['HIGH', 'MED', 'LOW', 'UNSET']);
const VALID_SIGNAL_TYPES   = new Set(['trial_update','regulatory','publication','conference','safety','news','other']);
const VALID_ACTIONS        = new Set(['ESCALATE','MONITOR','DISMISS','REVIEW']);
const VALID_OVERRIDE_STATS = new Set(['escalated','downgraded','locked','none']);


// ══════════════════════════════════════════════════════════════════
// 1. UTILITY FUNCTIONS
// ══════════════════════════════════════════════════════════════════
const numOr = (v, fallback) => {
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const clamp       = (n, min, max) => Math.max(min, Math.min(n, max));
const isoNow      = () => new Date().toISOString();
const round2      = (n) => Math.round(n * 100) / 100;
const safeStr     = (v, fb = '') => (v === null || v === undefined ? fb : String(v).trim() || fb);
const safeUpper   = (v, fb = '') => safeStr(v, fb).toUpperCase();
const safeLower   = (v, fb = '') => safeStr(v, fb).toLowerCase();
const safeBool    = (v) => v === true || v === 'true' || v === 1;

const validateEnum = (v, validSet, fallback) => {
  const u = safeUpper(v);
  return validSet.has(u) ? u : fallback;
};

const validateEnumLower = (v, validSet, fallback) => {
  const l = safeLower(v);
  return validSet.has(l) ? l : fallback;
};

const hoursAgo = (isoStr) => {
  if (!isoStr) return null;
  const ms = Date.now() - new Date(isoStr).getTime();
  return Number.isFinite(ms) ? round2(ms / 3600000) : null;
};


// ══════════════════════════════════════════════════════════════════
// 2. ACQUIRE INPUTS
// ══════════════════════════════════════════════════════════════════
const updateResult = $input.item.json;

let fullSignal;
try {
  fullSignal = $('Merge AI Output').item.json;
} catch (err) {
  throw new Error(
    '[OncoWatch:Restore] Cannot read "Merge AI Output" node. ' +
    'Verify exact node name. Original error: ' + err.message
  );
}

if (!updateResult || typeof updateResult !== 'object') {
  throw new Error('[OncoWatch:Restore] updateResult is null/not-object.');
}
if (!fullSignal || typeof fullSignal !== 'object') {
  throw new Error('[OncoWatch:Restore] fullSignal is null/not-object.');
}


// ══════════════════════════════════════════════════════════════════
// 3. NORMALIZE + VALIDATE ALL FIELDS
// ══════════════════════════════════════════════════════════════════
const signalId       = safeStr(fullSignal.source_id || fullSignal.id, null);
const drug           = safeStr(fullSignal.key_drug   || fullSignal.drug_name,  'Unknown');
const indication     = safeStr(fullSignal.key_indication || fullSignal.indication, 'Unknown');
const sponsor        = safeStr(fullSignal.sponsor, 'Unknown');
const phase          = safeStr(fullSignal.phase   || fullSignal.trial_phase,   'NA');
const trialStatus    = safeStr(fullSignal.status  || fullSignal.trial_status,  'NA');
const title          = safeStr(fullSignal.title,   'NA');
const source         = safeStr(fullSignal.source,  'unknown');
const url            = safeStr(fullSignal.url,     '');

const impactLevel    = validateEnum(fullSignal.impact_level, VALID_IMPACT_LEVELS, 'LOW');
const impactScore    = clamp(numOr(fullSignal.impact_score, 0), 0, 10);
const signalType     = validateEnumLower(fullSignal.signal_type, VALID_SIGNAL_TYPES, 'other');
const recAction      = validateEnum(fullSignal.recommended_action, VALID_ACTIONS, 'MONITOR');
const overrideStatus = validateEnumLower(fullSignal.override_status, VALID_OVERRIDE_STATS, 'none');
const overrideBy     = safeStr(fullSignal.override_by,     '');
const overrideReason = safeStr(fullSignal.override_reason, '');

const isUrgent       = safeBool(fullSignal.is_urgent);
const competitor     = safeBool(fullSignal.competitor_flag);
const aiProcessed    = safeBool(fullSignal.ai_processed);
const dbSuccess      = safeBool(updateResult.success);

const confidence     = clamp(numOr(fullSignal.score_breakdown?.confidence, 0), 0, 1);
const drivers        = Array.isArray(fullSignal.score_breakdown?.drivers) ? fullSignal.score_breakdown.drivers : [];
const risks          = Array.isArray(fullSignal.score_breakdown?.risks)   ? fullSignal.score_breakdown.risks   : [];

const version        = numOr(fullSignal.version,         1);
const scoringVersion = numOr(fullSignal.scoring_version, 0);
const retryCountAI   = numOr(fullSignal.retry_count,     0);
const retryCountSafe = numOr(fullSignal.retry_count_safe, 0);
const priorityBase   = numOr(fullSignal.priority_base,   null);

const ingestedAt     = fullSignal.ingested_at   || null;
const firstSeenAt    = fullSignal.first_seen_at || null;
const lastSeenAt     = fullSignal.last_seen_at  || null;

const computedAgeHours = hoursAgo(firstSeenAt) || numOr(fullSignal.age_hours, 0);

const dailySent  = safeBool(fullSignal.daily_sent);
const weeklySent = safeBool(fullSignal.weekly_sent);

const triageMeta    = fullSignal._triage_meta   || {};
const routingMeta   = fullSignal._routing_meta  || {};
const pipelineMeta  = fullSignal._meta          || {};


// ══════════════════════════════════════════════════════════════════
// 4. COMPOSITE PRIORITY SCORE (7-factor weighted model)
// ══════════════════════════════════════════════════════════════════
/*
  Factor                    Max contribution
  ─────────────────────────────────────────
  Base impact score         10.0  (direct passthrough)
  Competitor flag           +2.0
  Urgency flag              +2.0
  Override: escalated       +1.5
  Recency (<48h)            +1.0
  High confidence (≥0.75)   +0.75
  Moderate confidence       +0.5
  Override: downgraded      -2.0
  Capped at 10.0
*/
let priorityScore = impactScore;

if (competitor)                             priorityScore += 2.0;
if (isUrgent)                               priorityScore += 2.0;
if (overrideStatus === 'escalated')         priorityScore += 1.5;
if (overrideStatus === 'downgraded')        priorityScore -= 2.0;
if (computedAgeHours < URGENT_AGE_HOURS_THRESHOLD) priorityScore += 1.0;
if (confidence >= CONFIDENCE_HIGH_MIN)      priorityScore += 0.75;
else if (confidence >= CONFIDENCE_ALERT_MIN) priorityScore += 0.5;

priorityScore = clamp(round2(priorityScore), 0, 10);


// ══════════════════════════════════════════════════════════════════
// 5. ROUTE TIER DETERMINATION (9-tier ordered logic)
// ══════════════════════════════════════════════════════════════════
let routeTier;

if (!dbSuccess) {
  routeTier = ROUTE_TIERS.DB_FAILED;

} else if (!aiProcessed) {
  routeTier = ROUTE_TIERS.AI_FAILED;

} else if (
  priorityScore >= CRITICAL_PRIORITY_THRESHOLD ||
  (isUrgent && impactLevel === 'HIGH' && competitor) ||
  overrideStatus === 'locked'
) {
  routeTier = ROUTE_TIERS.CRITICAL;

} else if (impactLevel === 'HIGH' && competitor) {
  routeTier = ROUTE_TIERS.HIGH_COMPETITOR;

} else if (
  impactLevel === 'HIGH' ||
  priorityScore >= HIGH_PRIORITY_THRESHOLD
) {
  routeTier = ROUTE_TIERS.HIGH;

} else if (
  impactLevel === 'MED' &&
  (isUrgent || competitor || priorityScore >= MED_ELEVATED_THRESHOLD)
) {
  routeTier = ROUTE_TIERS.MED_ELEVATED;

} else if (impactLevel === 'MED') {
  routeTier = ROUTE_TIERS.MED;

} else if (recAction === 'DISMISS' || impactLevel === 'LOW') {
  routeTier = recAction === 'DISMISS'
    ? ROUTE_TIERS.DISMISS
    : ROUTE_TIERS.LOW;

} else {
  routeTier = ROUTE_TIERS.LOW;
}


// ══════════════════════════════════════════════════════════════════
// 6. ALERT CHANNELS
// ══════════════════════════════════════════════════════════════════
const alertChannels = [...(CHANNEL_MAP[routeTier] || [])];

// Inject urgent override channel if not already present
if (isUrgent && !alertChannels.includes('slack_exec')) {
  alertChannels.unshift('slack_exec');
}

// Deduplicate
const uniqueChannels = [...new Set(alertChannels)];


// ══════════════════════════════════════════════════════════════════
// 7. OVERRIDE COMPLIANCE CHECK
// ══════════════════════════════════════════════════════════════════
let overrideViolation = false;
let overrideViolationReason = null;

if (overrideStatus === 'escalated' && ['LOW', 'DISMISS'].includes(routeTier)) {
  overrideViolation = true;
  overrideViolationReason =
    `Signal was escalated by ${overrideBy || 'human'} but AI routed to ${routeTier}. Manual review required.`;
}
if (overrideStatus === 'locked' && routeTier !== ROUTE_TIERS.CRITICAL) {
  overrideViolation = true;
  overrideViolationReason =
    `Signal is locked by ${overrideBy || 'human'} but AI routed to ${routeTier}. Forced upgrade to CRITICAL.`;
  routeTier = ROUTE_TIERS.CRITICAL; // force upgrade
}
if (overrideStatus === 'downgraded' && routeTier === ROUTE_TIERS.CRITICAL) {
  overrideViolation = true;
  overrideViolationReason =
    `Signal was downgraded by ${overrideBy || 'human'} but AI still scored CRITICAL (score: ${priorityScore}). Flagged for review.`;
}


// ══════════════════════════════════════════════════════════════════
// 8. SIGNAL VELOCITY (version-based change rate)
// ══════════════════════════════════════════════════════════════════
let signalVelocity = null;
let velocityLabel  = 'STABLE';

if (firstSeenAt && lastSeenAt && version > 1) {
  const spanHours = hoursAgo(firstSeenAt) || 1;
  const versionsPerHour = round2((version - 1) / spanHours);
  signalVelocity = versionsPerHour;
  velocityLabel  =
    versionsPerHour >= 1.0  ? 'FAST'    :
    versionsPerHour >= 0.25 ? 'ACTIVE'  :
    versionsPerHour >= 0.05 ? 'SLOW'    : 'STABLE';
}


// ══════════════════════════════════════════════════════════════════
// 9. RETRY + DIGEST FLAGS
// ══════════════════════════════════════════════════════════════════
const shouldRetryAI  = !aiProcessed && retryCountAI  < MAX_RETRY_AI;
const shouldRetryDB  = !dbSuccess   && retryCountSafe < MAX_RETRY_DB;
const sendDaily      = !dailySent   && ['CRITICAL','HIGH_COMPETITOR','HIGH','MED_ELEVATED','MED'].includes(routeTier);
const sendWeekly     = !weeklySent  && !['DISMISS','LOW'].includes(routeTier);


// ══════════════════════════════════════════════════════════════════
// 10. AUDIT TRAIL ENTRY
// ══════════════════════════════════════════════════════════════════
const auditEntry = {
  event:             'SIGNAL_ROUTED',
  pipeline_version:  PIPELINE_VERSION,
  signal_id:         signalId,
  route_tier:        routeTier,
  notif_priority:    NOTIF_PRIORITY[routeTier] || 'P4',
  priority_score:    priorityScore,
  impact_level:      impactLevel,
  impact_score:      impactScore,
  confidence:        confidence,
  competitor_flag:   competitor,
  is_urgent:         isUrgent,
  override_status:   overrideStatus,
  override_violation: overrideViolation,
  db_success:        dbSuccess,
  ai_processed:      aiProcessed,
  signal_velocity:   signalVelocity,
  velocity_label:    velocityLabel,
  alert_channels:    uniqueChannels,
  timestamp:         isoNow(),
};


// ══════════════════════════════════════════════════════════════════
// 11. BUILD FINAL ENRICHED OUTPUT
// ══════════════════════════════════════════════════════════════════
const enriched = {
  // ── Original signal fields (all preserved) ──────────────────────
  id:                signalId,
  source_id:         signalId,
  source:            source,
  title:             title,
  drug_name:         drug,
  key_drug:          drug,
  indication:        indication,
  key_indication:    indication,
  sponsor:           sponsor,
  phase:             phase,
  status:            trialStatus,
  url:               url,
  raw_text:          fullSignal.raw_text       || null,
  ai_summary:        fullSignal.ai_summary     || '',
  ingested_at:       ingestedAt,
  first_seen_at:     firstSeenAt,
  last_seen_at:      lastSeenAt,
  version:           version,
  scoring_version:   scoringVersion,
  override_status:   overrideStatus,
  override_by:       overrideBy   || null,
  override_reason:   overrideReason || null,
  override_at:       fullSignal.override_at    || null,
  is_urgent:         isUrgent,
  priority_base:     priorityBase,
  age_hours:         computedAgeHours,
  daily_sent:        dailySent,
  weekly_sent:       weeklySent,
  retry_count:       retryCountAI,
