  },
  ai_processed:      aiProcessed,
  processed:         true,
  refusal:           fullSignal.refusal   || null,
  reasoning:         fullSignal.reasoning || null,

  // ── DB write result ──────────────────────────────────────────────
  success:           dbSuccess,

  // ── Routing outputs (used by Switch node) ───────────────────────
  route_tier:        routeTier,
  priority_score:    priorityScore,
  notif_priority:    NOTIF_PRIORITY[routeTier] || 'P4',
  alert_channels:    uniqueChannels,
  should_retry_ai:   shouldRetryAI,
  should_retry_db:   shouldRetryDB,
  send_daily:        sendDaily,
  send_weekly:       sendWeekly,

  // ── Override compliance ──────────────────────────────────────────
  override_violation:        overrideViolation,
