parameters.jsCode:
/**
 * ============================================================
 * OncoWatch — Format HIGH Alert
 * Version: 1.0.0
 * Builds Slack Block Kit + Email for HIGH tier signals
 * ============================================================
 */

const s = $input.item.json;
const isoNow  = () => new Date().toISOString();
const safeStr = (v, fb = 'N/A') =>
  (v === null || v === undefined || v === '') ? fb : String(v);

// ── Core fields ───────────────────────────────────────────────
const signalId      = safeStr(s.source_id || s.id);
const drug          = safeStr(s.key_drug  || s.drug_name);
const indication    = safeStr(s.key_indication || s.indication);
const sponsor       = safeStr(s.sponsor);
const phase         = safeStr(s.phase || s.trial_phase);
const trialStatus   = safeStr(s.status || s.trial_status);
const signalType    = safeStr(s.signal_type);
const impactLevel   = safeStr(s.impact_level, 'HIGH');
const impactScore   = s.impact_score   ?? 'N/A';
const priorityScore = s.priority_score ?? 'N/A';
const notifPriority = safeStr(s.notif_priority, 'P1');
const routeTier     = safeStr(s.route_tier);
const recAction     = safeStr(s.recommended_action);
const aiSummary     = safeStr(s.ai_summary);
const competitor    = !!s.competitor_flag;
const isUrgent      = !!s.is_urgent;
const velocityLabel = safeStr(s.velocity_label, 'STABLE');
const overrideStatus = safeStr(s.override_status, 'none');
const overrideBy    = safeStr(s.override_by, '');
const overrideReason = safeStr(s.override_reason, '');
const url           = safeStr(s.url, '');
const firstSeenAt   = safeStr(s.first_seen_at, '');
const ageHours      = s.age_hours ?? 'N/A';
const confidence    = s.score_breakdown?.confidence ?? 'N/A';

const alertChannels = Array.isArray(s.alert_channels)
  ? s.alert_channels.join(', ') : 'N/A';

const drivers = Array.isArray(s.score_breakdown?.drivers)
  ? s.score_breakdown.drivers.slice(0, 4).map(d => `• ${d}`).join('\n')
  : 'N/A';

const risks = Array.isArray(s.score_breakdown?.risks)
  ? s.score_breakdown.risks.slice(0, 3).map(r => `⚠ ${r}`).join('\n')
  : 'N/A';

const confDisplay = typeof confidence === 'number'
  ? (confidence * 100).toFixed(0) + '%'
  : confidence;

const overrideBlock = overrideStatus !== 'none'
  ? `\n*Override:* ${overrideStatus.toUpperCase()} by ${overrideBy || 'unknown'}\n*Reason:* ${overrideReason}`
  : '';

const violationBlock = s.override_violation
  ? `\n\n🔴 *OVERRIDE VIOLATION:*\n${safeStr(s.override_violation_reason)}`
  : '';

// ── Slack Block Kit ───────────────────────────────────────────
const slackBlocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `🔴 [${notifPriority}] HIGH Signal — ${drug}`,
      emoji: true
    }
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Drug:*\n${drug}` },
      { type: 'mrkdwn', text: `*Indication:*\n${indication}` },
      { type: 'mrkdwn', text: `*Sponsor:*\n${sponsor}` },
      { type: 'mrkdwn', text: `*Phase:*\n${phase}` },
      { type: 'mrkdwn', text: `*Trial Status:*\n${trialStatus}` },
      { type: 'mrkdwn', text: `*Signal Type:*\n${signalType}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Impact Level:*\n🔴 ${impactLevel}` },
      { type: 'mrkdwn', text: `*Impact Score:*\n${impactScore}/10` },
      { type: 'mrkdwn', text: `*Priority Score:*\n${priorityScore}/10` },
      { type: 'mrkdwn', text: `*Confidence:*\n${confDisplay}` },
      { type: 'mrkdwn', text: `*Competitor:*\n${competitor ? '✅ YES' : '❌ NO'}` },
      { type: 'mrkdwn', text: `*Urgent:*\n${isUrgent ? '⚡ YES' : 'NO'}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*AI Summary:*\n${aiSummary}`
    }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Key Drivers:*\n${drivers}` },
      { type: 'mrkdwn', text: `*Risks / Caveats:*\n${risks}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Recommended Action:*\n🔴 ${recAction}` },
      { type: 'mrkdwn', text: `*Signal Velocity:*\n${velocityLabel}` },
      { type: 'mrkdwn', text: `*Override:*\n${overrideStatus.toUpperCase()}${overrideBy ? ' by ' + overrideBy : ''}` },
      { type: 'mrkdwn', text: `*Alert Channels:*\n${alertChannels}` },
      { type: 'mrkdwn', text: `*First Seen:*\n${firstSeenAt}` },
      { type: 'mrkdwn', text: `*Age:*\n${ageHours} hrs` }
    ]
  },
  ...(overrideBlock || violationBlock ? [{
    type: 'section',
    text: { type: 'mrkdwn', text: `${overrideBlock}${violationBlock}` }
  }] : []),
  ...(url ? [{
    type: 'actions',
    elements: [{
      type: 'button',
      text: { type: 'plain_text', text: '🔗 View Source', emoji: true },
      url: url,
      style: 'primary'
    }]
  }] : []),
  { type: 'divider' },
  {
    type: 'context',
    elements: [{
      type: 'mrkdwn',
      text: `OncoWatch • Pipeline v${safeStr(s._triage_meta?.pipeline_version, 'N/A')} • Signal ID: ${signalId} • Routed at: ${isoNow()}`
    }]
  }
];

// ── Email ─────────────────────────────────────────────────────
const emailSubject =
  `[${notifPriority}] 🔴 HIGH CI Signal: ${drug} — ${indication}`;

const emailBody = `
HIGH IMPACT COMPETITIVE INTELLIGENCE SIGNAL
============================================
Priority:        ${notifPriority}
Route Tier:      ${routeTier}
Signal ID:       ${signalId}

DRUG & TRIAL
─────────────
Drug:            ${drug}
Indication:      ${indication}
Sponsor:         ${sponsor}
Phase:           ${phase}
Trial Status:    ${trialStatus}
Signal Type:     ${signalType}
Source URL:      ${url || 'N/A'}

TRIAGE SCORES
─────────────
Impact Level:    ${impactLevel}
Impact Score:    ${impactScore}/10
Priority Score:  ${priorityScore}/10
Confidence:      ${confDisplay}
Competitor Flag: ${competitor ? 'YES' : 'NO'}
Urgent:          ${isUrgent ? 'YES' : 'NO'}
Velocity:        ${velocityLabel}

AI SUMMARY
──────────
${aiSummary}

KEY DRIVERS
───────────
${drivers}

RISKS / CAVEATS
───────────────
${risks}

RECOMMENDED ACTION: ${recAction}

OVERRIDE
─────────
Status:    ${overrideStatus.toUpperCase()}
By:        ${overrideBy   || 'N/A'}
Reason:    ${overrideReason || 'N/A'}
Violation: ${s.override_violation ? 'YES — ' + safeStr(s.override_violation_reason) : 'NO'}

METADATA
─────────
First Seen:     ${firstSeenAt}
Age:            ${ageHours} hrs
Alert Channels: ${alertChannels}
Pipeline:       v${safeStr(s._triage_meta?.pipeline_version, 'N/A')}
`.trim();

// ── Audit row ─────────────────────────────────────────────────
const auditRow = {
  signal_id:          signalId,
  route_tier:         routeTier,
  notif_priority:     notifPriority,
  impact_level:       impactLevel,
  impact_score:       s.impact_score      ?? null,
  priority_score:     s.priority_score    ?? null,
  confidence:         typeof confidence === 'number' ? confidence : null,
  competitor_flag:    competitor,
  is_urgent:          isUrgent,
  override_status:    overrideStatus,
  override_violation: !!s.override_violation,
  recommended_action: recAction,
  signal_type:        signalType,
  alert_channels:     JSON.stringify(s.alert_channels || []),
  velocity_label:     velocityLabel,
  ai_summary:         aiSummary,
  pipeline_version:   safeStr(s._triage_meta?.pipeline_version, 'N/A'),
  routed_at:          isoNow(),
};

return [{
  json: {
    ...s,
    _alert: {
      slack_blocks:  slackBlocks,
      email_subject: emailSubject,
      email_body:    emailBody,
      audit_row:     auditRow,
      formatted_at:  isoNow(),
    }
  }
}];

