// ─────────────────────────────────────────────
const s = $input.item.json;

const isoNow = () => new Date().toISOString();

const safeStr = (v, fb = 'N/A') => {
  if (v === null || v === undefined) return fb;
  const out = String(v).trim();
  return out === '' ? fb : out;
};

const numOrNull = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const clamp = (n, min, max) => Math.max(min, Math.min(n, max));

// ─────────────────────────────────────────────
// 1. Basic validation
// ─────────────────────────────────────────────
if (!s || typeof s !== 'object') {
  throw new Error('[OncoWatch:Digest] Input item is null or not an object.');
}

if (!s.route_tier) {
  throw new Error('[OncoWatch:Digest] route_tier is missing — Switch wiring or Restore node is wrong.');
}

// ─────────────────────────────────────────────
// 2. Normalize core fields
// ─────────────────────────────────────────────
const signalId      = safeStr(s.source_id || s.id, null);
const drug          = safeStr(s.key_drug  || s.drug_name, 'Unknown');
const indication    = safeStr(s.key_indication || s.indication, 'Unknown');
const sponsor       = safeStr(s.sponsor, 'Unknown');
const phase         = safeStr(s.phase || s.trial_phase, 'NA');
const trialStatus   = safeStr(s.status || s.trial_status, 'NA');
const signalType    = safeStr(s.signal_type, 'other');

const impactLevel   = safeStr(s.impact_level, 'LOW').toUpperCase();
const impactScore   = numOrNull(s.impact_score);
const priorityScore = numOrNull(s.priority_score);
const notifPriority = safeStr(s.notif_priority, 'P3');
const routeTierRaw  = safeStr(s.route_tier);

// only allow known tiers
const VALID_TIERS = new Set(['MED_ELEVATED', 'MED', 'LOW', 'DISMISS']);
const routeTier   = VALID_TIERS.has(routeTierRaw) ? routeTierRaw : 'LOW';

const recAction   = safeStr(s.recommended_action, 'MONITOR').toUpperCase();
const aiSummary   = safeStr(s.ai_summary, '');
const competitor  = !!s.competitor_flag;
const isUrgent    = !!s.is_urgent;
const velocityLabel = safeStr(s.velocity_label, 'STABLE');
const url         = safeStr(s.url, '');
const firstSeenAt = safeStr(s.first_seen_at, '');
const ageHours    = numOrNull(s.age_hours);
const scoringVer  = numOrNull(s.scoring_version) ?? 0;

const confidence  = numOrNull(s.score_breakdown?.confidence);
const driversArr  = Array.isArray(s.score_breakdown?.drivers)
  ? s.score_breakdown.drivers
  : [];
const risksArr    = Array.isArray(s.score_breakdown?.risks)
  ? s.score_breakdown.risks
  : [];

// ─────────────────────────────────────────────
// 3. Tier label + risk class
// ─────────────────────────────────────────────
const tierLabel =
  routeTier === 'MED_ELEVATED' ? 'MED (Elevated)' :
  routeTier === 'MED'          ? 'MED' :
  routeTier === 'LOW'          ? 'LOW' :
  routeTier === 'DISMISS'      ? 'DISMISS' :
  routeTier;

// risk class for digest-level filtering
let riskClass;
if (impactLevel === 'HIGH') {
  riskClass = 'HIGH';
} else if (impactLevel === 'MED') {
  riskClass = 'MED';
} else {
  riskClass = 'LOW';
}

// ─────────────────────────────────────────────
// 4. Short formatted bullets for Slack/Email digest
// ─────────────────────────────────────────────
const impactScoreDisplay = impactScore !== null ? `${impactScore}/10` : 'N/A';
const confDisplay = confidence !== null
  ? `${Math.round(clamp(confidence, 0, 1) * 100)}%`
  : 'N/A';

const digestLine =
  `• [${tierLabel}] ${drug} — ${indication} ` +
  `(Impact: ${impactLevel} ${impactScoreDisplay}, ` +
  `Confidence: ${confDisplay}, ` +
  `Competitor: ${competitor ? 'YES' : 'NO'}, ` +
  `Velocity: ${velocityLabel})`;

// ─────────────────────────────────────────────
// 5. Digest entry object (compact but rich)
// ─────────────────────────────────────────────
const digestEntry = {
  signal_id:        signalId,
  route_tier:       routeTier,
  tier_label:       tierLabel,
  risk_class:       riskClass,
  notif_priority:   notifPriority,
  drug,
  indication,
  sponsor,
  phase,
  status:           trialStatus,
  impact_level:     impactLevel,
  impact_score:     impactScore,
  priority_score:   priorityScore,
  confidence:       confidence,
  competitor_flag:  competitor,
  is_urgent:        isUrgent,
  velocity_label:   velocityLabel,
  recommended_action: recAction,
  signal_type:      signalType,
  url:              url || null,
  ai_summary:       aiSummary,
  first_seen_at:    firstSeenAt || null,
  age_hours:        ageHours,
  scoring_version:  scoringVer,
  created_at:       isoNow(),
};

// ─────────────────────────────────────────────
// 6. Drivers / risks — trimmed for digest
// ─────────────────────────────────────────────
const driversDigest = driversArr.length
  ? driversArr.slice(0, 3).map(d => `• ${d}`).join('\n')
  : 'N/A';

const risksDigest = risksArr.length
  ? risksArr.slice(0, 2).map(r => `⚠ ${r}`).join('\n')
  : 'N/A';

// ─────────────────────────────────────────────
// 7. Archive blob (full payload for cold storage)
// ─────────────────────────────────────────────
const archiveBlob = {
  ...s,
  archived_at: isoNow(),
};

// ─────────────────────────────────────────────
// 8. Routing hints for downstream queues
// ─────────────────────────────────────────────
const isDailyCandidate =
  ['MED_ELEVATED', 'MED'].includes(routeTier) && !s.send_daily && !s.dead_letter;

const isWeeklyCandidate =
  routeTier === 'LOW' && !s.send_weekly && !s.dead_letter;

const isDismissCandidate =
  routeTier === 'DISMISS';

// ─────────────────────────────────────────────
// 9. Enriched output
// ─────────────────────────────────────────────
return [{
  json: {
    ...s,
    _digest: {
      line:          digestLine,
      entry:         digestEntry,
      tier_label:    tierLabel,
      risk_class:    riskClass,
      drivers_text:  driversDigest,
      risks_text:    risksDigest,
      is_daily_candidate:  isDailyCandidate,
      is_weekly_candidate: isWeeklyCandidate,
      is_dismiss_candidate: isDismissCandidate,
      formatted_at:  isoNow(),
    },
    _archive: archiveBlob,
  }
}];

