INSERT INTO ci_daily_digest_queue (
  signal_id, route_tier, digest_line, digest_json
) VALUES (
  $1, $2, $3, $4
);

INSERT INTO ci_archive (
  signal_id, route_tier, impact_level, impact_score, payload
) VALUES (
  $1, $2, $3, $4, $5
);

parameters.jsCode:
const item = $input.item;
const s = item.json;

// Build the audit JSON payload (you can tweak this)
const auditPayload = {
  signal_id:       s.source_id || s.id || 'N/A',
  route_tier:      s.route_tier || 'N/A',
  notif_priority:  s.notif_priority || 'P0',
  impact_level:    s.impact_level || 'N/A',
  impact_score:    s.impact_score ?? null,
  priority_score:  s.priority_score ?? null,
  confidence:      typeof s.score_breakdown?.confidence === 'number'
                     ? s.score_breakdown.confidence
                     : null,
  competitor_flag: !!s.competitor_flag,
  is_urgent:       !!s.is_urgent,
  override_status: s.override_status || 'none',
  override_violation: !!s.override_violation,
  recommended_action: s.recommended_action || 'N/A',
  signal_type:     s.signal_type || 'N/A',
  alert_channels:  s.alert_channels || [],
  velocity_label:  s.velocity_label || 'N/A',
  ai_summary:      s.ai_summary || '',
  routed_at:       new Date().toISOString(),
  pipeline_version: s._triage_meta?.pipeline_version || 'N/A',
};

const jsonString = JSON.stringify(auditPayload, null, 2);

return [{
  json: item.json,
  binary: {
    oncowatch_audit: {
      data: Buffer.from(jsonString).toString('base64'),
      fileName: `oncowatch_audit_${s.source_id || s.id || 'unknown'}.json`,
      mimeType: 'application/json',
    },
  },
}];
